                                <label className="flex items-center gap-2"><input type="checkbox" name="dCheck" checked={formData.checklist?.dCheck || false} onChange={handleChecklistChange} className="focus:ring-red-500 h-4 w-4 text-red-600 border-slate-300 rounded"/> D-Check</label>
                                <label className="flex items-center gap-2"><input type="checkbox" name="battery" checked={formData.checklist?.battery || false} onChange={handleChecklistChange} className="focus:ring-red-500 h-4 w-4 text-red-600 border-slate-300 rounded"/> Battery</label>
                                <label className="flex items-center gap-2"><input type="checkbox" name="spares" checked={formData.checklist?.spares || false} onChange={handleChecklistChange} className="focus:ring-red-500 h-4 w-4 text-red-600 border-slate-300 rounded"/> Spares</label>
                                <label className="flex items-center gap-2"><input type="checkbox" name="bd" checked={formData.checklist?.bd || false} onChange={handleChecklistChange} className="focus:ring-red-500 h-4 w-4 text-red-600 border-slate-300 rounded"/> BD</label>
                                <label className="flex items-center gap-2"><input type="checkbox" name="radiatorDescaling" checked={formData.checklist?.radiatorDescaling || false} onChange={handleChecklistChange} className="focus:ring-red-500 h-4 w-4 text-red-600 border-slate-300 rounded"/> Radiator Descaling</label>
                                <label className="flex items-center gap-2"><input type="checkbox" name="others" checked={formData.checklist?.others || false} onChange={handleChecklistChange} className="focus:ring-red-500 h-4 w-4 text-red-600 border-slate-300 rounded"/> Others</label>
                            </div>
                            {formData.checklist?.others && (
                                <div className="mt-3">
                                    <label htmlFor="checklistRemarks" className="block text-sm font-medium text-slate-700 dark:text-slate-300">Remarks for "Others"</label>
                                    <input
                                        type="text"
                                        id="checklistRemarks"
                                        name="checklistRemarks"
                                        value={formData.checklistRemarks || ''}
                                        onChange={handleInputChange}
                                        placeholder="Enter remarks..."
                                        className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:outline-none focus:ring-red-500 focus:border-red-500"
                                    />
                                </div>
                            )}
                        </div>
                        <div className="pt-2 border-t dark:border-slate-700">
                             <label htmlFor="dispatchRemarks" className="block text-sm font-medium text-slate-700 dark:text-slate-300">Dispatch Pending Remarks (Reason for not shipping)</label>
                             <textarea
                                 id="dispatchRemarks"
                                 name="dispatchRemarks"
                                 value={formData.dispatchRemarks || ''}
                                 onChange={handleInputChange}
                                 rows={2}
                                 placeholder="Reason why fully available items are not shipped..."
                                 className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:outline-none focus:ring-blue-500 focus:border-blue-500"
                             />
                        </div>
                    </div>

                    {!isCreateMode && (
                        <>
                         <div className="space-y-3 pt-6 border-t dark:border-slate-700">
                           <h3 className="text-lg font-medium text-slate-800 dark:text-white">Item Status</h3>
                           {formData.items.map((item, index) => (
                             <div key={index} className="bg-slate-50 dark:bg-slate-800/50 p-3 rounded-lg">
                               <div className="flex justify-between items-center">
                                 <div>
                                   <p className="font-bold text-slate-800 dark:text-slate-100">{item.partNumber}</p>
                                   <p className={`text-sm font-semibold ${getStatusColor(item.status)}`}>{item.status}</p>
                                 </div>
                                 <div className="relative">
                                   <button 
                                     type="button" 
                                     onClick={() => setActiveDropdownIndex(activeDropdownIndex === index ? null : index)}
                                     className="flex items-center gap-1 px-2 py-1 text-xs text-slate-600 dark:text-slate-300 bg-white dark:bg-slate-700 border dark:border-slate-600 rounded-md hover:bg-slate-100 dark:hover:bg-slate-600"
                                   >
                                     Update <ChevronDownIcon className={`w-3 h-3 transition-transform ${activeDropdownIndex === index ? 'rotate-180' : ''}`}/>
                                   </button>

                                   {activeDropdownIndex === index && (
                                     <div className="absolute right-0 bottom-full mb-2 w-48 bg-white dark:bg-slate-800 rounded-md shadow-lg ring-1 ring-black ring-opacity-5 z-20">
                                       {Object.values(POItemStatus).map(s => (
                                         <button 
                                           key={s} 
                                           type="button" 
                                           onClick={() => {
                                             onUpdateItemStatus?.(existingPO.id, item.partNumber, s);
                                             setActiveDropdownIndex(null);
                                           }} 
                                           className="block w-full text-left px-3 py-2 text-sm text-slate-700 dark:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-700 disabled:opacity-50 disabled:cursor-not-allowed" 
                                           disabled={item.status === s}
                                         >
                                           {s}
                                         </button>
                                       ))}
                                     </div>
                                   )}
                                 </div>
                               </div>
                               {item.status === POItemStatus.NotAvailable && onGetSuggestion && (<div className="mt-2 pt-2 border-t dark:border-slate-600"><button type="button" onClick={() => onGetSuggestion(item)} className="flex items-center gap-1.5 px-2 py-1 text-xs font-semibold text-amber-700 bg-amber-100 dark:text-amber-200 dark:bg-amber-900/50 rounded-md hover:bg-amber-200 dark:hover:bg-amber-900 w-full justify-center"><SparklesIcon className="w-3.5 h-3.5"/> Suggest Procurement Strategy</button></div>)}
                             </div>
                           ))}
                         </div>
                         <div className="space-y-3 pt-6 border-t dark:border-slate-700"><h3 className="text-lg font-semibold text-slate-800 dark:text-white mb-2">Activity Log</h3><ul className="space-y-3 max-h-48 overflow-y-auto pr-2">{logs.slice().reverse().map(log => (<li key={log.id} className="text-sm border-l-2 pl-3 border-slate-200 dark:border-slate-600"><p className="text-slate-700 dark:text-slate-200">{log.action}</p><p className="text-xs text-slate-500 dark:text-slate-400">{new Date(log.timestamp).toLocaleString()}</p></li>))}</ul></div>
                        </>
                    )}
                </div>
            </div>
          <div className="p-4 bg-slate-50 dark:bg-slate-800/50 border-t dark:border-slate-700 flex justify-end gap-3 sticky bottom-0 rounded-b-xl">
            <button type="button" onClick={onClose} className="px-4 py-2 text-sm font-medium text-slate-700 bg-white dark:bg-slate-700 dark:text-slate-200 border dark:border-slate-600 rounded-md hover:bg-slate-50 dark:hover:bg-slate-600">Cancel</button>
            <button type="submit" className="px-4 py-2 text-sm font-medium text-white bg-red-600 rounded-md hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500">{isCreateMode ? 'Create PO' : 'Save Changes'}</button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default POModal;

import React, { useState, useCallback } from 'react';
import { ArrowUpTrayIcon, DocumentPlusIcon, PlusIcon, XMarkIcon, ArrowDownTrayIcon } from './icons';
import { MAIN_BRANCHES, BRANCH_STRUCTURE, BULK_UPLOAD_HEADERS, ITEM_CATEGORIES } from '../constants';
import { downloadTemplate } from '../utils/export';
import { OrderStatus, OverallPOStatus, FulfillmentStatus, POItemStatus } from '../types';

interface UploadPaneProps {
    onSaveSingleOrder: (order: any) => void;
    onBulkUpload: (orders: any[]) => void;
}

const initialItemState = { 
    partNumber: '', // Item: Item Name
    itemDesc: '', // Item: Item Description
    itemType: '', // Item: Item Type
    quantity: 1, 
    rate: 0, // Unit Price
    discount: 0, // Discount Amount
    stockAvailable: 0,
    stockInHand: 0,
    baseAmount: 0,
    taxAmount: 0,
    grossAmount: 0,
    category: '',
    itemRemarks: '',
    oaNo: '',
    oaDate: '',
    gst: 18,
    status: POItemStatus.NotAvailable,
};

const initialOrderState = {
    mainBranch: '',
    subBranch: '',
    accountName: '',
    poNo: '',
    poDate: new Date().toISOString().split('T')[0],
    soNo: '',
    soDate: new Date().toISOString().split('T')[0],
    poStatus: OverallPOStatus.Available,
    generalRemarks: '',
    etaAvailable: '',
    billingPlan: '',
    materials: FulfillmentStatus.Available,
    paymentStatus: 'Pending',
    items: [initialItemState],
    billingAddress: '',
    billToGSTIN: '',
    shippingAddress: '',
    shipToGSTIN: '',
    quoteNumber: '',
    saleType: 'Credit' as 'Cash' | 'Credit',
    creditTerms: 30,
};

const UploadPane: React.FC<UploadPaneProps> = ({ onSaveSingleOrder, onBulkUpload }) => {
    const [dragging, setDragging] = useState(false);
    const [order, setOrder] = useState(initialOrderState);

    const parseCSVAndUpload = (file: File) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            const text = e.target?.result as string;
            const lines = text.split(/\r?\n/).filter(l => l.trim());
            if (lines.length < 2) return;

            const rawHeaders = lines[0].split(',');
            const headers = rawHeaders.map(h => h.replace(/^\uFEFF/, '').trim().toLowerCase());

            const getColIdx = (exactHeader: string) => {
                return headers.indexOf(exactHeader.toLowerCase());
            };

            const branchIdx = getColIdx('Main -Branch');
            const subBranchIdx = getColIdx('Sub - branch');
            const soNoIdx = getColIdx('SO.NO');
            const soDateIdx = getColIdx('SO DATE');
            const poNoIdx = getColIdx('PO.NO');
            const poDateIdx = getColIdx('PO DATE');
            const accountIdx = getColIdx('Account Name');
            const typeIdx = getColIdx('Item: Item Type');
            const poStatusIdx = getColIdx('Po Status');
            const genRemIdx = getColIdx('General Remarks');
            const oaNoIdx = getColIdx('Oa No');
            const oaDateIdx = getColIdx('Oa Date');
            const etaIdx = getColIdx('Eta Available');
            const billPlanIdx = getColIdx('Billing Plan');
            const materialsIdx = getColIdx('Materials');
            const payStatusIdx = getColIdx('Payment Status');

            const nameIdx = getColIdx('Item: Item Name');
            const descIdx = getColIdx('Item: Item Description');
            const qtyIdx = getColIdx('Quantity');
            const stockAvailIdx = getColIdx('Stock Available');
            const stockHandIdx = getColIdx('Stock In Hand');
            const priceIdx = getColIdx('Unit Price');
            const baseAmtIdx = getColIdx('Base Amount');
            const catIdx = getColIdx('Category');
            const discIdx = getColIdx('Discount Amount');
            const taxAmtIdx = getColIdx('Tax Amount');
            const grossAmtIdx = getColIdx('Gross Amount');
            const itemRemIdx = getColIdx('Item Remarks');

            const billAddrIdx = getColIdx('Billing Address');
            const billGstIdx = getColIdx('Bill To GSTIN');
            const shipAddrIdx = getColIdx('Shipping Address');
            const shipGstIdx = getColIdx('Ship To GSTIN');
            const quoteIdx = getColIdx('Quote Number');

            const rows = lines.slice(1).map(line => {
                const values: string[] = [];
                let current = '';
                let inQuotes = false;
                for (let i = 0; i < line.length; i++) {
                    const char = line[i];
                    if (char === '"') {
                        if (inQuotes && line[i+1] === '"') { current += '"'; i++; }
                        else inQuotes = !inQuotes;
                    } else if (char === ',' && !inQuotes) {
                        values.push(current.trim());
                        current = '';
                    } else current += char;
                }
                values.push(current.trim());
                return values;
            });

            const getStr = (row: string[], idx: number, fallback = '') => (idx !== -1 && row[idx]) ? row[idx].trim() : fallback;
            const getNum = (row: string[], idx: number, fallback = 0) => (idx !== -1 && row[idx]) ? parseFloat(row[idx].replace(/[^0-9.]/g, '')) || fallback : fallback;

            const poGroups: Record<string, any[]> = {};
            rows.forEach(row => {
                const id = getStr(row, poNoIdx) || 'CSV-' + Math.random();
                if (!poGroups[id]) poGroups[id] = [];
                poGroups[id].push(row);
            });

            const parsedPOs = Object.entries(poGroups).map(([poNumber, group]) => {
                const first = group[0];

                const items = group.map(row => ({
                    partNumber: getStr(row, nameIdx, 'N/A'),
                    itemType: getStr(row, typeIdx),
                    itemDesc: getStr(row, descIdx),
                    quantity: getNum(row, qtyIdx, 1),
                    stockAvailable: getNum(row, stockAvailIdx),
                    stockInHand: getNum(row, stockHandIdx),
                    rate: getNum(row, priceIdx),
                    baseAmount: getNum(row, baseAmtIdx),
                    category: getStr(row, catIdx),
                    discount: getNum(row, discIdx),
                    taxAmount: getNum(row, taxAmtIdx),
                    grossAmount: getNum(row, grossAmtIdx),
                    itemRemarks: getStr(row, itemRemIdx),
                    oaNo: getStr(row, oaNoIdx),
                    oaDate: getStr(row, oaDateIdx),
                    status: POItemStatus.NotAvailable
                }));

                const materialsStatus = getStr(first, materialsIdx) as FulfillmentStatus;

                return {
                    mainBranch: getStr(first, branchIdx, 'Unassigned'),
                    subBranch: getStr(first, subBranchIdx),
                    salesOrderNumber: getStr(first, soNoIdx),
                    soDate: getStr(first, soDateIdx),
                    poNumber: poNumber,
                    poDate: getStr(first, poDateIdx, new Date().toISOString().split('T')[0]),
                    customerName: getStr(first, accountIdx, 'Unknown'),
                    status: getStr(first, poStatusIdx) as OverallPOStatus || OverallPOStatus.Available,
                    generalRemarks: getStr(first, genRemIdx),
                    etaAvailable: getStr(first, etaIdx),
                    billingPlan: getStr(first, billPlanIdx),
                    materials: materialsStatus || FulfillmentStatus.Available,
                    fulfillmentStatus: materialsStatus || FulfillmentStatus.Available,
                    paymentStatus: getStr(first, payStatusIdx),
                    billingAddress: getStr(first, billAddrIdx),
                    billToGSTIN: getStr(first, billGstIdx),
                    shippingAddress: getStr(first, shipAddrIdx),
                    shipToGSTIN: getStr(first, shipGstIdx),
                    quoteNumber: getStr(first, quoteIdx),
                    items,
                    createdAt: new Date().toISOString()
                };
            });

            onBulkUpload(parsedPOs);
        };
        reader.readAsText(file);
    };

    const handleOrderChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
        const { name, value } = e.target;
        if (name === 'mainBranch') {
            setOrder(prev => ({ ...prev, mainBranch: value, subBranch: '' }));
        } else {
            setOrder(prev => ({ ...prev, [name]: value }));
        }
    };

    const handleItemChange = (index: number, e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setOrder(prev => {
            const newItems = prev.items.map((item, i) => {
                if (i === index) {
                    return { ...item, [name]: value };
                }
                return item;
            });
            return { ...prev, items: newItems };
        });
    };

    const addItem = () => {
        setOrder(prev => ({ ...prev, items: [...prev.items, { ...initialItemState }] }));
    };

    const removeItem = (index: number) => {
        setOrder(prev => ({ ...prev, items: prev.items.filter((_, i) => i !== index) }));
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSaveSingleOrder(order);
        setOrder(initialOrderState);
    };

    const handleDrop = (e: React.DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
        setDragging(false);
        if (e.dataTransfer.files && e.dataTransfer.files[0]) {
            parseCSVAndUpload(e.dataTransfer.files[0]);
        }
    };

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            parseCSVAndUpload(e.target.files[0]);
        }
    };

    const handleDragEnter = (e: React.DragEvent) => { e.preventDefault(); e.stopPropagation(); setDragging(true); };
    const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); e.stopPropagation(); setDragging(true); };
    const handleDragLeave = (e: React.DragEvent) => { e.preventDefault(); e.stopPropagation(); setDragging(false); };

    const renderField = (label: string, name: string, type = 'text', options?: {value: string, label: string}[], required = false) => (
        <div>
            <label htmlFor={name} className="block text-sm font-medium text-slate-700 dark:text-slate-300">{label}</label>
            {type === 'select' ? (
                <select id={name} name={name} value={(order as any)[name]} onChange={handleOrderChange} required={required} className="mt-1 block w-full px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500">
                    <option value="">Select...</option>
                    {options?.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                </select>
            ) : (
                <input type={type} id={name} name={name} value={(order as any)[name]} onChange={handleOrderChange} required={required} className="mt-1 block w-full px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500" />
            )}
        </div>
    );

    return (
        <div className="container mx-auto p-4 sm:p-6 lg:p-8">
            <div className="grid grid-cols-1 gap-8">
                <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-lg border border-slate-200 dark:border-slate-700">
                    <h2 className="text-2xl font-black mb-6 flex items-center gap-3 text-slate-800 dark:text-white">
                        <DocumentPlusIcon className="w-8 h-8 text-red-500" />
                        <span>Manual Sales Order Entry</span>
                    </h2>
                    <form onSubmit={handleSubmit} className="space-y-8">
                        {/* Header Section */}
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 p-6 bg-slate-50 dark:bg-slate-900/30 rounded-xl">
                            <div className="md:col-span-3"><h3 className="text-lg font-bold text-slate-800 dark:text-white border-b pb-2 mb-2">Basic Information</h3></div>
                            {renderField("Main -Branch", "mainBranch", "select", MAIN_BRANCHES.map(b => ({value: b, label: b})), true)}
                            {renderField("Sub - branch", "subBranch", "select", order.mainBranch ? BRANCH_STRUCTURE[order.mainBranch].map(sb => ({value: sb, label: sb})) : [], true)}
                            {renderField("Account Name", "accountName", "text", [], true)}
                            {renderField("SO.NO", "soNo", "text", [], true)}
                            {renderField("SO DATE", "soDate", "date", [], true)}
                            {renderField("PO.NO", "poNo", "text", [], true)}
                            {renderField("PO DATE", "poDate", "date", [], true)}
                            {renderField("Po Status", "poStatus", "select", Object.values(OverallPOStatus).map(s => ({value: s, label: s})))}
                            {renderField("Payment Status", "paymentStatus", "text")}
                            {renderField("Billing Plan", "billingPlan", "text")}
                            {renderField("Materials (Fulfillment)", "materials", "select", Object.values(FulfillmentStatus).map(s => ({value: s, label: s})))}
                            {renderField("Eta Available", "etaAvailable", "date")}
                            <div className="md:col-span-3">
                                <label className="block text-sm font-medium">General Remarks</label>
                                <textarea name="generalRemarks" value={order.generalRemarks} onChange={handleOrderChange} rows={2} className="mt-1 block w-full px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white"></textarea>
                            </div>
                        </div>

                        {/* Items Section */}
                        <div className="space-y-4">
                           <div className="flex justify-between items-center"><h3 className="text-lg font-bold text-slate-800 dark:text-white">Line Items</h3><button type="button" onClick={addItem} className="flex items-center gap-2 text-sm font-bold text-red-600 hover:text-red-800"><PlusIcon className="w-5 h-5"/> Add Line Item</button></div>
                           {order.items.map((item, index) => (
                               <div key={index} className="p-6 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl shadow-sm relative space-y-4">
                                 {order.items.length > 1 && <button type="button" onClick={() => removeItem(index)} className="absolute top-4 right-4 text-slate-400 hover:text-red-500"><XMarkIcon className="w-6 h-6"/></button>}
                                 <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                                     <div className="md:col-span-2"><label className="text-xs font-bold uppercase tracking-tight text-slate-500">Item: Item Name</label><input type="text" name="partNumber" value={item.partNumber} onChange={(e) => handleItemChange(index, e)} required className="w-full text-base font-bold p-2 border-b-2 border-slate-200 focus:border-red-500 bg-transparent outline-none"/></div>
                                     <div><label className="text-xs font-bold uppercase tracking-tight text-slate-500">Item: Item Type</label><input type="text" name="itemType" value={item.itemType} onChange={(e) => handleItemChange(index, e)} className="w-full text-base p-2 border-b border-slate-200 bg-transparent outline-none"/></div>
                                     <div>
                                        <label className="text-xs font-bold uppercase tracking-tight text-slate-500">Category</label>
                                        <select 
                                            name="category" 
                                            value={item.category} 
                                            onChange={(e) => handleItemChange(index, e)} 
                                            className="w-full text-base p-2 border-b border-slate-200 bg-transparent outline-none dark:bg-slate-800 dark:text-white"
                                        >
                                            <option value="">Select Category</option>
                                            {ITEM_CATEGORIES.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                                        </select>
                                     </div>
                                     <div className="md:col-span-4"><label className="text-xs font-bold uppercase tracking-tight text-slate-500">Item: Item Description</label><input type="text" name="itemDesc" value={item.itemDesc} onChange={(e) => handleItemChange(index, e)} className="w-full text-base p-2 border-b border-slate-200 bg-transparent outline-none"/></div>
                                 </div>
                                 <div className="grid grid-cols-2 md:grid-cols-6 gap-4">
                                     <div><label className="text-xs">Quantity</label><input type="number" name="quantity" value={item.quantity} onChange={(e) => handleItemChange(index, e)} className="w-full p-2 bg-slate-50 rounded border-none"/></div>
                                     <div><label className="text-xs">Unit Price</label><input type="number" name="rate" value={item.rate} onChange={(e) => handleItemChange(index, e)} className="w-full p-2 bg-slate-50 rounded border-none"/></div>
                                     <div><label className="text-xs">Discount Amount</label><input type="number" name="discount" value={item.discount} onChange={(e) => handleItemChange(index, e)} className="w-full p-2 bg-slate-50 rounded border-none"/></div>
                                     <div><label className="text-xs">Base Amount</label><input type="number" name="baseAmount" value={item.baseAmount} onChange={(e) => handleItemChange(index, e)} className="w-full p-2 bg-slate-50 rounded border-none"/></div>
                                     <div><label className="text-xs">Tax Amount</label><input type="number" name="taxAmount" value={item.taxAmount} onChange={(e) => handleItemChange(index, e)} className="w-full p-2 bg-slate-50 rounded border-none"/></div>
                                     <div><label className="text-xs">Gross Amount</label><input type="number" name="grossAmount" value={item.grossAmount} onChange={(e) => handleItemChange(index, e)} className="w-full p-2 bg-red-50 font-bold rounded border-none"/></div>
                                 </div>
                                 <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                                     <div><label className="text-xs">Stock Available</label><input type="number" name="stockAvailable" value={item.stockAvailable} onChange={(e) => handleItemChange(index, e)} className="w-full p-2 bg-slate-50 rounded border-none"/></div>
                                     <div><label className="text-xs">Stock In Hand</label><input type="number" name="stockInHand" value={item.stockInHand} onChange={(e) => handleItemChange(index, e)} className="w-full p-2 bg-slate-50 rounded border-none"/></div>
                                     <div>
                                        <label className="text-xs">Item Status</label>
                                        <select 
                                            name="status" 
                                            value={item.status} 
                                            onChange={(e) => handleItemChange(index, e)} 
                                            className="w-full p-2 bg-slate-50 rounded border-none text-sm outline-none"
                                        >
                                            {Object.values(POItemStatus).map(s => <option key={s} value={s}>{s}</option>)}
                                        </select>
                                     </div>
                                     <div><label className="text-xs">Oa No</label><input type="text" name="oaNo" value={item.oaNo} onChange={(e) => handleItemChange(index, e)} className="w-full p-2 bg-slate-50 rounded border-none"/></div>
                                     <div><label className="text-xs">Oa Date</label><input type="date" name="oaDate" value={item.oaDate} onChange={(e) => handleItemChange(index, e)} className="w-full p-2 bg-slate-50 rounded border-none"/></div>
                                 </div>
                                 <div><label className="text-xs font-bold text-slate-500">Item Remarks</label><input type="text" name="itemRemarks" value={item.itemRemarks} onChange={(e) => handleItemChange(index, e)} className="w-full text-sm p-2 border-b border-slate-200 bg-transparent outline-none"/></div>
                               </div>
                           ))}
                        </div>

                        {/* Footer Section */}
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 p-6 bg-slate-50 dark:bg-slate-900/30 rounded-xl">
                           <div className="md:col-span-2"><h3 className="text-lg font-bold text-slate-800 dark:text-white border-b pb-2 mb-2">Delivery & Documentation</h3></div>
                           {renderField("Billing Address", "billingAddress")}
                           {renderField("Bill To GSTIN", "billToGSTIN")}
                           {renderField("Shipping Address", "shippingAddress")}
                           {renderField("Ship To GSTIN", "shipToGSTIN")}
                           {renderField("Quote Number", "quoteNumber")}
                        </div>

                        <div className="flex justify-end gap-3 pt-6">
                           <button type="button" onClick={() => setOrder(initialOrderState)} className="px-8 py-3 text-sm font-bold text-slate-600 bg-white border border-slate-200 rounded-lg hover:bg-slate-50">Reset Form</button>
                           <button type="submit" className="px-12 py-3 text-sm font-black text-white bg-red-600 rounded-lg hover:bg-red-700 shadow-xl active:scale-95 transition-all">Save Sales Order</button>
                        </div>
                    </form>
                </div>

                <div className="bg-white dark:bg-slate-800 p-10 rounded-2xl shadow-xl border-2 border-dashed border-slate-300 dark:border-slate-700">
                    <div 
                        onDragEnter={handleDragEnter}
                        onDragOver={handleDragOver}
                        onDragLeave={handleDragLeave}
                        onDrop={handleDrop}
                        className={`flex flex-col items-center justify-center p-12 rounded-xl transition-all ${dragging ? 'bg-red-50 border-red-500 scale-105' : 'bg-slate-50 dark:bg-slate-900/50 border-transparent'}`}
                    >
                        <div className="p-5 bg-white dark:bg-slate-800 rounded-full shadow-lg mb-6">
                            <ArrowUpTrayIcon className={`w-16 h-16 ${dragging ? 'text-red-600 animate-bounce' : 'text-slate-300'}`} />
                        </div>
                        <h3 className="text-2xl font-black text-slate-800 dark:text-white mb-2">Bulk Import (CSV)</h3>
                        <p className="text-slate-500 dark:text-slate-400 text-center mb-8 max-w-md">Drag and drop your spreadsheet here. The format must exactly match the 33 columns defined in the template.</p>

                        <div className="flex flex-col sm:flex-row gap-4">
                            <label className="flex items-center gap-3 px-8 py-4 bg-red-600 text-white rounded-lg hover:bg-red-700 cursor-pointer shadow-xl font-black transition-all active:scale-95">
                                <PlusIcon className="w-6 h-6" />
                                Choose CSV File
                                <input type="file" className="hidden" accept=".csv" onChange={handleFileSelect} />
                            </label>
                            <button onClick={downloadTemplate} className="flex items-center gap-3 px-8 py-4 bg-slate-800 text-white rounded-lg hover:bg-slate-900 font-black transition-all shadow-xl active:scale-95">
                                <ArrowDownTrayIcon className="w-6 h-6" />
                                Download Master Template
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default UploadPane;

import React, { useState, useEffect } from 'react';
import type { PurchaseOrder, POItem, LogEntry } from '../types';
import { POItemStatus, OrderStatus, FulfillmentStatus } from '../types';
import { MAIN_BRANCHES, BRANCH_STRUCTURE, ITEM_CATEGORIES } from '../constants';
import { PlusIcon, XMarkIcon, SparklesIcon, ChevronDownIcon } from './icons';

interface POModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave?: (po: Omit<PurchaseOrder, 'id' | 'createdAt' | 'status'>) => void;
  onUpdate?: (po: PurchaseOrder) => void;
  onUpdateItemStatus?: (poId: string, partNumber: string, status: POItemStatus) => void;
  existingPO?: PurchaseOrder;
  logs?: LogEntry[];
  onGetSuggestion?: (item: POItem) => void;
}

const initialItemState: POItem = { 
    partNumber: '', 
    quantity: 1, 
    rate: 0, 
    status: POItemStatus.NotAvailable, 
    itemDesc: '', 
    discount: 0, 
    gst: 0,
    stockAvailable: 0,
    stockInHand: 0,
    allocatedQuantity: 0,
    deliveryQuantity: 0,
    invoicedQuantity: 0,
    itemType: '',
    oaNo: '',
    oaDate: '',
    category: '',
};

const initialPOState: Omit<PurchaseOrder, 'id' | 'createdAt' | 'status'> = {
    poNumber: '',
    customerName: '',
    poDate: new Date().toISOString().split('T')[0],
    items: [initialItemState],
    saleType: 'Credit',
    paymentStatus: null,
    paymentNotes: '',
    creditTerms: 30,
    mainBranch: '',
    subBranch: '',
    salesOrderNumber: '',
    systemRemarks: '',
    orderStatus: OrderStatus.OpenOrders,
    fulfillmentStatus: FulfillmentStatus.NotAvailable,
    invoiceNumber: '',
    invoiceDate: '',
    billingAddress: '',
    billToGSTIN: '',
    shippingAddress: '',
    shipToGSTIN: '',
    quoteNumber: '',
    pfAvailable: false,
    checklist: {
        bCheck: false,
        cCheck: false,
        dCheck: false,
        battery: false,
        spares: false,
        bd: false,
        radiatorDescaling: false,
        others: false,
    },
    checklistRemarks: '',
    dispatchRemarks: '',
};


const POModal: React.FC<POModalProps> = ({ isOpen, onClose, onSave, onUpdate, onUpdateItemStatus, existingPO, logs = [], onGetSuggestion }) => {
  const [formData, setFormData] = useState(initialPOState);
  const [activeDropdownIndex, setActiveDropdownIndex] = useState<number | null>(null);

  const isCreateMode = !existingPO;

  useEffect(() => {
    if (isOpen && existingPO) {
        setFormData({ 
            ...existingPO,
            checklist: {
                bCheck: existingPO.checklist?.bCheck || false,
                cCheck: existingPO.checklist?.cCheck || false,
                dCheck: existingPO.checklist?.dCheck || false,
                battery: existingPO.checklist?.battery || false,
                spares: existingPO.checklist?.spares || false,
                bd: existingPO.checklist?.bd || false,
                radiatorDescaling: existingPO.checklist?.radiatorDescaling || false,
                others: existingPO.checklist?.others || false,
            },
            dispatchRemarks: existingPO.dispatchRemarks || '',
        });
    } else if (isOpen && !existingPO) {
        setFormData(initialPOState);
    }
    setActiveDropdownIndex(null);
  }, [isOpen, existingPO]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value, type } = e.target;
    const isCheckbox = type === 'checkbox';
    const checkedValue = (e.target as HTMLInputElement).checked;

    if (name === 'mainBranch') {
        setFormData(prev => ({ ...prev, mainBranch: value, subBranch: '' }));
    } else if (name === 'pfAvailable') {
        setFormData(prev => ({ ...prev, pfAvailable: checkedValue }));
    } else {
        setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleChecklistChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, checked } = e.target;
    setFormData(prev => ({
        ...prev,
        checklist: { ...prev.checklist!, [name]: checked }
    }));
  };

  const handleSaleTypeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const saleType = e.target.value as 'Cash' | 'Credit';
    setFormData(prev => ({
        ...prev,
        saleType,
        paymentStatus: saleType === 'Cash' ? 'Pending' : null,
        creditTerms: saleType === 'Credit' ? 30 : 0
    }));
  };

  const handleItemChange = (index: number, field: keyof POItem, value: string | number) => {
    setFormData(prev => {
        const newItems = prev.items.map((item, i) => {
            if (i === index) {
                return { ...item, [field]: value };
            }
            return item;
        });
        return { ...prev, items: newItems };
    });
  };

  const addItem = () => {
    setFormData(prev => ({...prev, items: [...prev.items, initialItemState]}));
  };

  const removeItem = (index: number) => {
    setFormData(prev => ({...prev, items: prev.items.filter((_, i) => i !== index)}));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isCreateMode && onSave) {
        onSave(formData);
    } else if (!isCreateMode && onUpdate && existingPO) {
        onUpdate({ ...formData, id: existingPO.id, createdAt: existingPO.createdAt, status: existingPO.status });
    }
    onClose();
  };

  const getStatusColor = (status: POItemStatus) => {
    const colors: { [key in POItemStatus]: string } = {
        [POItemStatus.Available]: 'text-green-600 dark:text-green-400',
        [POItemStatus.PartiallyAvailable]: 'text-yellow-600 dark:text-yellow-400',
        [POItemStatus.NotAvailable]: 'text-red-600 dark:text-red-400',
        [POItemStatus.Dispatched]: 'text-blue-600 dark:text-blue-400',
    };
    return colors[status];
  }

  const showInvoiceFields = formData.orderStatus === OrderStatus.Invoiced || formData.orderStatus === OrderStatus.PartiallyInvoiced || formData.orderStatus === OrderStatus.ShippedInSystemDC;

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-60 z-40 flex justify-center items-center p-4">
      <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl w-full max-w-6xl max-h-[90vh] flex flex-col">
        <div className="flex justify-between items-center p-5 border-b border-slate-200 dark:border-slate-700">
          <h2 className="text-2xl font-bold text-slate-800 dark:text-white">{isCreateMode ? 'New Purchase Order' : `PO Details: ${existingPO.poNumber}`}</h2>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700">
            <XMarkIcon className="w-6 h-6 text-slate-600 dark:text-slate-300" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto">
            <div className="p-6 md:grid md:grid-cols-2 md:gap-x-8 md:gap-y-6">
                <div className="space-y-6">
                    <div className="space-y-4 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-lg">
                        <h3 className="text-lg font-medium text-slate-800 dark:text-white">PO Information</h3>
                        <div className="grid grid-cols-2 gap-4">
                             <div>
                                <label htmlFor="customerName" className="block text-sm font-medium text-slate-700 dark:text-slate-300">Customer Name</label>
                                <input type="text" id="customerName" name="customerName" value={formData.customerName} onChange={handleInputChange} required className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                            </div>
                             <div>
                                <label htmlFor="mainBranch" className="block text-sm font-medium text-slate-700 dark:text-slate-300">Main Branch</label>
                                <select id="mainBranch" name="mainBranch" value={formData.mainBranch} onChange={handleInputChange} className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:outline-none focus:ring-red-500 focus:border-red-500">
                                    <option value="">Select Main Branch</option>
                                    {MAIN_BRANCHES.map(b => <option key={b} value={b}>{b}</option>)}
                                </select>
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label htmlFor="poNumber" className="block text-sm font-medium text-slate-700 dark:text-slate-300">PO Number</label>
                                <input type="text" id="poNumber" name="poNumber" value={formData.poNumber} onChange={handleInputChange} required className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                            </div>
                             <div>
                                <label htmlFor="subBranch" className="block text-sm font-medium text-slate-700 dark:text-slate-300">Sub Branch</label>
                                <select id="subBranch" name="subBranch" value={formData.subBranch} onChange={handleInputChange} disabled={!formData.mainBranch} className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:outline-none focus:ring-red-500 focus:border-red-500 disabled:opacity-50">
                                    <option value="">Select Sub Branch</option>
                                    {formData.mainBranch && BRANCH_STRUCTURE[formData.mainBranch]?.map(sb => <option key={sb} value={sb}>{sb}</option>)}
                                </select>
                            </div>
                        </div>
                         <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label htmlFor="poDate" className="block text-sm font-medium text-slate-700 dark:text-slate-300">PO Date</label>
                                <input type="date" id="poDate" name="poDate" value={formData.poDate} onChange={handleInputChange} required className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                            </div>
                             <div>
                                <label htmlFor="orderStatus" className="block text-sm font-medium text-slate-700 dark:text-slate-300">Order Status</label>
                                <select id="orderStatus" name="orderStatus" value={formData.orderStatus} onChange={handleInputChange} className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:outline-none focus:ring-red-500 focus:border-red-500">
                                    {Object.values(OrderStatus).map(s => <option key={s} value={s}>{s}</option>)}
                                </select>
                            </div>
                        </div>

                        {showInvoiceFields && (
                            <div className="grid grid-cols-2 gap-4 p-3 bg-yellow-50 dark:bg-yellow-900/20 rounded-lg border border-yellow-200 dark:border-yellow-700/50">
                                <div>
                                    <label htmlFor="invoiceNumber" className="block text-sm font-medium text-slate-700 dark:text-slate-300">Invoice Number</label>
                                    <input type="text" id="invoiceNumber" name="invoiceNumber" value={formData.invoiceNumber || ''} onChange={handleInputChange} required className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-yellow-500 focus:border-yellow-500"/>
                                </div>
                                <div>
                                    <label htmlFor="invoiceDate" className="block text-sm font-medium text-slate-700 dark:text-slate-300">Invoice Date</label>
                                    <input type="date" id="invoiceDate" name="invoiceDate" value={formData.invoiceDate || ''} onChange={handleInputChange} required className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-yellow-500 focus:border-yellow-500"/>
                                </div>
                            </div>
                        )}

                         <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label htmlFor="salesOrderNumber" className="block text-sm font-medium text-slate-700 dark:text-slate-300">Sales Order No.</label>
                                <input type="text" id="salesOrderNumber" name="salesOrderNumber" value={formData.salesOrderNumber} onChange={handleInputChange} className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                            </div>
                            <div>
                                <label htmlFor="fulfillmentStatus" className="block text-sm font-medium text-slate-700 dark:text-slate-300">Materials / Fulfillment</label>
                                <select id="fulfillmentStatus" name="fulfillmentStatus" value={formData.fulfillmentStatus} onChange={handleInputChange} className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:outline-none focus:ring-red-500 focus:border-red-500">
                                    {Object.values(FulfillmentStatus).map(s => <option key={s} value={s}>{s}</option>)}
                                </select>
                            </div>
                        </div>

                         <div className="grid grid-cols-1 gap-4">
                             <div>
                                <label htmlFor="quoteNumber" className="block text-sm font-medium text-slate-700 dark:text-slate-300">Quote Number</label>
                                <input type="text" id="quoteNumber" name="quoteNumber" value={formData.quoteNumber || ''} onChange={handleInputChange} className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                             </div>
                         </div>
                    </div>
                    <div className="space-y-4 pt-6 border-t dark:border-slate-700">
                        <h3 className="text-lg font-medium text-slate-800 dark:text-white">Items</h3>
                        {formData.items.map((item, index) => (
                          <div key={index} className="space-y-2 p-3 bg-slate-50 dark:bg-slate-800/50 rounded-lg">
                            <div className="flex justify-between">
                               <input type="text" placeholder="Item Name / Part Number" value={item.partNumber} onChange={e => handleItemChange(index, 'partNumber', e.target.value)} required className="w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                               {formData.items.length > 1 && (<button type="button" onClick={() => removeItem(index)} className="ml-2 text-red-500 hover:text-red-700 p-2 rounded-full hover:bg-red-100 dark:hover:bg-red-900/50"><XMarkIcon className="w-5 h-5"/></button>)}
                            </div>
                            <div className="grid grid-cols-2 gap-2">
                                <select 
                                    value={item.category || ''} 
                                    onChange={e => handleItemChange(index, 'category', e.target.value)} 
                                    className="w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"
                                >
                                    <option value="">Select Category</option>
                                    {ITEM_CATEGORIES.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                                </select>
                                <input type="text" placeholder="Item Type" value={item.itemType || ''} onChange={e => handleItemChange(index, 'itemType', e.target.value)} className="w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                            </div>
                            <textarea placeholder="Item Description" value={item.itemDesc} onChange={e => handleItemChange(index, 'itemDesc', e.target.value)} rows={1} className="w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500" />
                            <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
                                <input type="number" placeholder="Qty" min="1" value={item.quantity} onChange={e => handleItemChange(index, 'quantity', parseInt(e.target.value, 10))} required className="w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                                <input type="number" placeholder="Rate" min="0.01" step="0.01" value={item.rate} onChange={e => handleItemChange(index, 'rate', parseFloat(e.target.value))} required className="w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                                <input type="number" placeholder="Discount" min="0" step="0.01" value={item.discount} onChange={e => handleItemChange(index, 'discount', parseFloat(e.target.value))} className="w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                                <input type="number" placeholder="GST %" min="0" step="0.01" value={item.gst} onChange={e => handleItemChange(index, 'gst', parseFloat(e.target.value))} className="w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                            </div>

                            <div className="mt-3 pt-2 border-t border-dashed border-slate-300 dark:border-slate-700">
                                <p className="text-xs font-bold text-slate-700 dark:text-slate-300 mb-2 uppercase tracking-wide">Stock & Fulfillment Details</p>
                                <div className="grid grid-cols-2 sm:grid-cols-5 gap-2">
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">Stock Avail.</label>
                                        <input type="number" value={item.stockAvailable} onChange={e => handleItemChange(index, 'stockAvailable', parseInt(e.target.value, 10))} className="w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">Stock InHand</label>
                                        <input type="number" value={item.stockInHand} onChange={e => handleItemChange(index, 'stockInHand', parseInt(e.target.value, 10))} className="w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">Allocated</label>
                                        <input type="number" value={item.allocatedQuantity} onChange={e => handleItemChange(index, 'allocatedQuantity', parseInt(e.target.value, 10))} className="w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">Delivered</label>
                                        <input type="number" value={item.deliveryQuantity} onChange={e => handleItemChange(index, 'deliveryQuantity', parseInt(e.target.value, 10))} className="w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">Invoiced</label>
                                        <input type="number" value={item.invoicedQuantity} onChange={e => handleItemChange(index, 'invoicedQuantity', parseInt(e.target.value, 10))} className="w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500"/>
                                    </div>
                                </div>
                            </div>

                            <div className="mt-3 pt-2 border-t border-dashed border-slate-300 dark:border-slate-700">
                                <p className="text-xs font-bold text-slate-700 dark:text-slate-300 mb-2 uppercase tracking-wide">Order Acknowledgement (OA) Details</p>
                                <div className="grid grid-cols-2 gap-4">
