                                        </select>
                                     </div>
                                     <div><label className="text-xs">Oa No</label><input type="text" name="oaNo" value={item.oaNo} onChange={(e) => handleItemChange(index, e)} className="w-full p-2 bg-slate-50 rounded border-none"/></div>
