import { PurchaseOrder } from '../types';
import { BULK_UPLOAD_HEADERS } from '../constants';

const convertToCSV = (data: PurchaseOrder[]): string => {
    const headers = BULK_UPLOAD_HEADERS;
    const rows: string[] = [];

    const safe = (str: any) => {
        if (str === undefined || str === null) return '""';
        const s = String(str).replace(/"/g, '""');
        return `"${s}"`;
    };

    data.forEach(po => {
        const items = po.items && po.items.length > 0 ? po.items : [{} as any];

        items.forEach(item => {
            const row = [
                safe(po.mainBranch),
                safe(po.subBranch),
                safe(po.customerName),
                safe(po.salesOrderNumber),
                safe(po.soDate),
                safe(po.poNumber),
                safe(po.poDate),
                safe(po.status),
                safe(po.saleType),
                safe(po.creditTerms),
                safe(po.billingPlan),
                safe(po.materials),
                safe(po.etaAvailable),
                safe(po.generalRemarks),
                safe(item.partNumber),
                safe(item.itemType),
                safe(item.category),
                safe(item.itemDesc),
                safe(item.quantity),
                safe(item.rate),
                safe(item.discount),
                safe(item.baseAmount),
                safe(item.taxAmount),
                safe(item.grossAmount),
                safe(item.stockAvailable),
                safe(item.stockInHand),
                safe(item.status),
                safe(item.oaNo),
                safe(item.oaDate),
                safe(item.itemRemarks),
                safe(po.billingAddress),
                safe(po.billToGSTIN),
                safe(po.shippingAddress),
                safe(po.shipToGSTIN),
                safe(po.quoteNumber)
            ];
            rows.push(row.join(','));
        });
    });

    return [headers.join(','), ...rows].join('\n');
};

export const exportToCSV = (data: PurchaseOrder[], filename: string = 'purchase_orders_detailed.csv'): void => {
    const csvString = convertToCSV(data);
    const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    if (link.download !== undefined) {
        const url = URL.createObjectURL(blob);
        link.setAttribute('href', url);
        link.setAttribute('download', filename);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    }
};

